from haystack.dataclasses import Document
from typing import Any

def validate_retriever_output(pipeline_output: dict[str, Any]) -> bool:
    docs = pipeline_output.get('documents')
    if not docs:
        return False
    return all(isinstance(doc, Document) for doc in docs[:10]) and all(hasattr(doc, 'content') for doc in docs[:10])
